"use client";

import {
  useLayoutEffect,
  useState,
  type MouseEvent as ReactMouseEvent,
} from "react";
import { useFlip } from "../hooks/useFlip";
import { usePrefersReducedMotion } from "../hooks/usePrefersReducedMotion";

type Tile = {
  id: string;
  /** grid footprint modifier — see styles.css .slate-tile--* */
  size: "hero" | "wide" | "box";
  figure: string;
  unit: string;
  title: string;
  titleKo: string;
  line: string;
  lineKo: string;
  detail: string;
  detailKo: string;
};

const TILES: Tile[] = [
  {
    id: "battery",
    size: "hero",
    figure: "6",
    unit: "weeks",
    title: "Battery",
    titleKo: "배터리",
    line: "Six weeks of mornings on one charge.",
    lineKo: "한 번의 충전으로 여섯 주의 아침.",
    detail:
      "E-ink spends power only when the page changes. Between pages — between thoughts — the slate is as off as a printed book. Charge it in June; notice the cable again in August.",
    detailKo:
      "전자잉크는 페이지가 바뀔 때만 전기를 씁니다. 페이지와 페이지 사이, 생각과 생각 사이에는 인쇄된 책만큼 꺼져 있습니다. 6월에 충전하면, 케이블은 8월에나 다시 생각납니다.",
  },
  {
    id: "display",
    size: "wide",
    figure: "300",
    unit: "ppi",
    title: "Hanji display",
    titleKo: "한지 디스플레이",
    line: "Light falls into it, not off it.",
    lineKo: "빛이 튕기지 않고 스며드는 화면.",
    detail:
      "The glass is micro-etched, so light lands and stays — the way it settles into hanji fiber. No glare at noon, no glow at midnight. At 300 ppi the letterforms have edges, not pixels.",
    detailKo:
      "유리 표면에 미세한 결을 새겼습니다. 빛은 튕겨 나가지 않고 한지의 섬유처럼 스며듭니다. 한낮에도 번쩍이지 않고, 한밤에도 빛나지 않습니다. 300ppi에서는 글자에 픽셀이 아니라 획이 보입니다.",
  },
  {
    id: "pen",
    size: "box",
    figure: "4.6",
    unit: "ms",
    title: "Pen latency",
    titleKo: "펜 지연 시간",
    line: "Closer than ink.",
    lineKo: "잉크보다 가깝게.",
    detail:
      "4.6 milliseconds between your hand and the mark — ink takes longer to leave the nib. The pen never charges and never pairs. It is a pen.",
    detailKo:
      "손끝과 획 사이 4.6밀리초. 잉크가 펜촉을 떠나는 시간보다 짧습니다. 펜은 충전도, 페어링도 하지 않습니다. 그냥 펜입니다.",
  },
  {
    id: "privacy",
    size: "box",
    figure: "0",
    unit: "clouds",
    title: "Offline by design",
    titleKo: "설계된 오프라인",
    line: "Your words stay in your pocket.",
    lineKo: "글은 주머니 속에 머뭅니다.",
    detail:
      "No account. No cloud. No telemetry. Your notes leave the slate only over a cable, only when you say so.",
    detailKo:
      "계정 없음. 클라우드 없음. 수집 없음. 글은 당신이 허락할 때만, 케이블을 타고만 밖으로 나갑니다.",
  },
  {
    id: "weight",
    size: "wide",
    figure: "168",
    unit: "g",
    title: "Weight",
    titleKo: "무게",
    line: "Lighter than the notebook it replaces.",
    lineKo: "대신할 공책보다 가볍습니다.",
    detail:
      "168 grams — a thin notebook and half a pencil. The magnesium back is one sheet; nothing rattles, nothing flexes.",
    detailKo:
      "168그램. 얇은 공책 한 권과 연필 반 자루의 무게입니다. 마그네슘 등판은 한 장으로 이어져 있어 덜컹이지도, 휘지도 않습니다.",
  },
  {
    id: "light",
    size: "wide",
    figure: "2700",
    unit: "K",
    title: "Front light",
    titleKo: "전면 조명",
    line: "Warm light for late pages.",
    lineKo: "늦은 페이지를 위한 따뜻한 빛.",
    detail:
      "The front light starts at candle-warm 2700 K and never shines at your eyes — only at the page, like a lamp over a desk.",
    detailKo:
      "전면 조명은 촛불처럼 따뜻한 2700K에서 시작합니다. 빛은 눈이 아니라 페이지를 비춥니다. 책상 위의 스탠드처럼.",
  },
];

/**
 * Section 02 — the bento grid, and the page's signature move.
 *
 * Activating a tile expands it to the full grid width via a shared-element
 * FLIP: rects are captured before the state change (First), the grid
 * reflows in one React commit (Last), every moved tile is inverted back
 * onto its old box and released a frame later (Invert-Play). Content
 * wrappers get the inverse scale so type never stretches. See useFlip.
 *
 * Accessibility contract:
 * - the toggle is a real <button> in the tile heading, aria-expanded +
 *   aria-controls; the whole tile is a convenience click target on top.
 * - collapsed tiles stay fully readable (figure, title, one line).
 * - detail hiding is gated behind .slate-js — without JavaScript every
 *   detail paragraph is simply visible.
 * - reduced motion: capture() is never called, so the layout snaps.
 */
export default function BentoGrid() {
  const [open, setOpen] = useState<string | null>(null);
  const reduced = usePrefersReducedMotion();
  const flip = useFlip();

  const toggle = (id: string) => {
    if (!reduced) flip.capture();
    setOpen((prev) => (prev === id ? null : id));
  };

  useLayoutEffect(() => {
    flip.play();
  }, [open, flip]);

  const onTileClick = (id: string) => (e: ReactMouseEvent<HTMLElement>) => {
    // The heading button handles itself; clicks inside the open detail
    // (e.g. selecting text) should never collapse the tile.
    const target = e.target as HTMLElement;
    if (target.closest("button, a, .slate-tile__detail")) return;
    toggle(id);
  };

  return (
    <section className="slate-bento" aria-labelledby="slate-bento-title">
      <div className="slate-sechead">
        <span className="slate-sechead__no" aria-hidden="true">
          02
        </span>
        <h2 className="slate-sechead__title" id="slate-bento-title">
          The parts that matter <span lang="ko">중요한 것들</span>
        </h2>
        <p className="slate-sechead__note">
          Tap a tile. <span lang="ko">타일을 눌러 보세요.</span>
        </p>
      </div>

      <ul className="slate-bento__grid">
        {TILES.map((t) => {
          const isOpen = open === t.id;
          return (
            <li
              key={t.id}
              ref={flip.setOuter(t.id)}
              className={`slate-tile slate-tile--${t.size}${isOpen ? " is-open" : ""}`}
              onClick={onTileClick(t.id)}
            >
              <div className="slate-tile__body" ref={flip.setInner(t.id)}>
                <p className="slate-tile__readout">
                  <span className="slate-tile__figure">{t.figure}</span>
                  <span className="slate-tile__unit">{t.unit}</span>
                </p>
                <h3 className="slate-tile__title">
                  <button
                    type="button"
                    className="slate-tile__toggle"
                    aria-expanded={isOpen}
                    aria-controls={`slate-tile-detail-${t.id}`}
                    onClick={() => toggle(t.id)}
                  >
                    <span className="slate-tile__name">
                      {t.title} <span lang="ko">{t.titleKo}</span>
                    </span>
                    <span className="slate-tile__plus" aria-hidden="true" />
                  </button>
                </h3>
                <p className="slate-tile__line">
                  {t.line} <span lang="ko">{t.lineKo}</span>
                </p>
                <div
                  id={`slate-tile-detail-${t.id}`}
                  className="slate-tile__detail"
                >
                  <p>{t.detail}</p>
                  <p lang="ko">{t.detailKo}</p>
                </div>
              </div>
            </li>
          );
        })}
      </ul>
    </section>
  );
}

"use client";

import { useCallback, useRef } from "react";
import { usePrefersReducedMotion } from "../hooks/usePrefersReducedMotion";
import { useScrollProgress } from "../hooks/useScrollProgress";

type Layer = {
  id: string;
  /** final translateY at full explode, px in viewBox units */
  spread: number;
  /** assembled center y of the plate */
  cy: number;
  label: string;
  labelKo: string;
};

const LAYERS: Layer[] = [
  { id: "glass", spread: -132, cy: 222, label: "etched glass · 0.4 mm", labelKo: "새김 유리" },
  { id: "panel", spread: -44, cy: 260, label: "e-ink panel · 300 ppi", labelKo: "전자잉크 패널" },
  { id: "battery", spread: 44, cy: 298, label: "2,900 mAh · six weeks", labelKo: "여섯 주짜리 배터리" },
  { id: "back", spread: 132, cy: 336, label: "magnesium · one sheet", labelKo: "마그네슘 한 장" },
];

/** Explode timing: plates travel while p ∈ [0.08, 0.70]. */
const EXPLODE_START = 0.08;
const EXPLODE_SPAN = 0.62;
/** Callout i draws while p ∈ [0.5 + 0.09i, 0.72 + 0.09i]. */
const DRAW_START = 0.5;
const DRAW_STAGGER = 0.09;
const DRAW_SPAN = 0.22;

const clamp01 = (v: number) => Math.min(1, Math.max(0, v));
const smoothstep = (v: number) => v * v * (3 - 2 * v);

/**
 * Section 03 — the exploded device, scrubbed by scroll.
 *
 * The section is 280vh tall (JS-gated in CSS); a sticky stage holds the
 * SVG. Scroll progress drives, per frame: a translateY on each layer group
 * (glass and back travel 3× farther than panel and battery — the parallax
 * that sells the depth), a stroke-dashoffset on each callout line
 * (pathLength=1, so the draw is 1→0 with no length measuring), and an
 * opacity fade on each label. Transform / dashoffset / opacity only — the
 * scrub never causes layout.
 *
 * The server-rendered state is the ASSEMBLED diagram with all callouts
 * drawn and labels visible; the callout group moves with its plate, so
 * the label always points at the part. No JS, or reduced motion, simply
 * keeps that state (and the CSS collapses the 280vh runway).
 */
export default function ExplodedView() {
  const sectionRef = useRef<HTMLElement | null>(null);
  const groupRefs = useRef<Array<SVGGElement | null>>([]);
  const lineRefs = useRef<Array<SVGPathElement | null>>([]);
  const labelRefs = useRef<Array<SVGTextElement | null>>([]);
  const reduced = usePrefersReducedMotion();

  const apply = useCallback((p: number) => {
    const e = smoothstep(clamp01((p - EXPLODE_START) / EXPLODE_SPAN));
    LAYERS.forEach((layer, i) => {
      const g = groupRefs.current[i];
      if (g) {
        g.style.transform = `translate3d(0, ${(layer.spread * e).toFixed(2)}px, 0)`;
      }
      const t = clamp01((p - (DRAW_START + i * DRAW_STAGGER)) / DRAW_SPAN);
      const line = lineRefs.current[i];
      if (line) line.style.strokeDashoffset = String(1 - t);
      const label = labelRefs.current[i];
      if (label) label.style.opacity = String(clamp01(t * 1.4));
    });
  }, []);

  useScrollProgress(sectionRef, apply, !reduced);

  return (
    <section
      ref={sectionRef}
      className="slate-exploded"
      aria-labelledby="slate-exploded-title"
    >
      <div className="slate-exploded__sticky">
        <div className="slate-sechead">
          <span className="slate-sechead__no" aria-hidden="true">
            03
          </span>
          <h2 className="slate-sechead__title" id="slate-exploded-title">
            What&rsquo;s inside <span lang="ko">안쪽</span>
          </h2>
          <p className="slate-sechead__note">
            Keep scrolling — the slate opens.{" "}
            <span lang="ko">스크롤하면 열립니다.</span>
          </p>
        </div>

        <svg
          className="slate-exploded__svg"
          viewBox="0 0 640 520"
          role="img"
          aria-label="Exploded diagram of the slate — etched glass, e-ink panel, battery, and magnesium back separate as you scroll. 분해도: 새김 유리, 전자잉크 패널, 배터리, 마그네슘 등판이 스크롤에 따라 벌어집니다."
        >
          {LAYERS.map((layer, i) => (
            <g
              key={layer.id}
              ref={(el) => {
                groupRefs.current[i] = el;
              }}
              className="slate-exploded__layer"
            >
              <g className={`slate-plate slate-plate--${layer.id}`}>
                <rect
                  className="slate-plate__slab"
                  x="90"
                  y={layer.cy - 17}
                  width="280"
                  height="34"
                  rx="17"
                />
                {layer.id === "glass" ? (
                  <line
                    className="slate-plate__sheen"
                    x1="150"
                    y1={layer.cy + 9}
                    x2="192"
                    y2={layer.cy - 9}
                  />
                ) : null}
                {layer.id === "panel" ? (
                  <g className="slate-plate__text">
                    <line x1="130" y1={layer.cy - 6} x2="290" y2={layer.cy - 6} />
                    <line x1="130" y1={layer.cy} x2="250" y2={layer.cy} />
                    <line x1="130" y1={layer.cy + 6} x2="270" y2={layer.cy + 6} />
                  </g>
                ) : null}
                {layer.id === "battery" ? (
                  <>
                    <rect
                      className="slate-plate__terminal"
                      x="330"
                      y={layer.cy - 5}
                      width="14"
                      height="10"
                      rx="3"
                    />
                    <text className="slate-plate__stamp" x="112" y={layer.cy + 4}>
                      2,900 mAh
                    </text>
                  </>
                ) : null}
                {layer.id === "back" ? (
                  <>
                    <circle className="slate-plate__emboss" cx="120" cy={layer.cy} r="4" />
                    <text
                      className="slate-plate__stamp slate-plate__stamp--etch"
                      x="230"
                      y={layer.cy + 4}
                      textAnchor="middle"
                    >
                      HANJI SLATE
                    </text>
                  </>
                ) : null}
              </g>

              {/* the callout travels with its plate, so it always points at the part */}
              <g className="slate-exploded__callout">
                <path
                  ref={(el) => {
                    lineRefs.current[i] = el;
                  }}
                  className="slate-exploded__line"
                  d={`M374 ${layer.cy} H430`}
                  pathLength={1}
                  strokeDasharray={1}
                  strokeDashoffset={0}
                />
                <text
                  ref={(el) => {
                    labelRefs.current[i] = el;
                  }}
                  className="slate-exploded__label"
                  x="438"
                  y={layer.cy - 1}
                >
                  {layer.label}
                  <tspan className="slate-exploded__labelKo" lang="ko" x="438" dy="17">
                    {layer.labelKo}
                  </tspan>
                </text>
              </g>
            </g>
          ))}
        </svg>

        {/* Narrow screens hide the in-SVG callouts and read this instead. */}
        <ol className="slate-exploded__legend">
          <li>
            etched glass · 0.4 mm <span lang="ko">새김 유리</span>
          </li>
          <li>
            e-ink panel · 300 ppi <span lang="ko">전자잉크 패널</span>
          </li>
          <li>
            battery · 2,900 mAh <span lang="ko">여섯 주짜리 배터리</span>
          </li>
          <li>
            magnesium back · one sheet <span lang="ko">마그네슘 한 장</span>
          </li>
        </ol>
      </div>
    </section>
  );
}

"use client";

import { useEffect, useRef } from "react";
import DeviceArt from "./DeviceArt";
import { usePrefersReducedMotion } from "../hooks/usePrefersReducedMotion";

/**
 * Section 01 — the calm warm stage.
 * Name, one tagline, one spec line, and the device on a soft shadow.
 *
 * Pointer parallax: on fine pointers the slate drifts up to ±7px toward
 * the cursor while its shadow drifts the opposite way at half depth —
 * two planes, lerped (k = 0.09 per 60fps-normalized frame), capped, and
 * self-stopping: the rAF loop parks itself once both planes settle.
 * Touch devices and prefers-reduced-motion never start the loop; the CSS
 * float on the SVG itself (also reduced-motion-gated) keeps the device
 * feeling lighter than air without any pointer at all.
 */
export default function Hero() {
  const stageRef = useRef<HTMLDivElement | null>(null);
  const deviceRef = useRef<HTMLDivElement | null>(null);
  const shadowRef = useRef<HTMLDivElement | null>(null);
  const reduced = usePrefersReducedMotion();

  useEffect(() => {
    if (reduced) return;
    if (!window.matchMedia("(hover: hover) and (pointer: fine)").matches) {
      return;
    }
    const stage = stageRef.current;
    const device = deviceRef.current;
    const shadow = shadowRef.current;
    if (!stage || !device || !shadow) return;

    let raf = 0;
    let running = false;
    let last = 0;
    let tx = 0; // target, -1..1
    let ty = 0;
    let cx = 0; // current
    let cy = 0;

    const frame = (now: number) => {
      const dt = last === 0 ? 16.7 : Math.min(48, now - last);
      last = now;
      const k = 1 - Math.pow(1 - 0.09, dt / 16.7);
      cx += (tx - cx) * k;
      cy += (ty - cy) * k;
      device.style.transform = `translate3d(${(cx * 7).toFixed(2)}px, ${(cy * 5).toFixed(2)}px, 0)`;
      shadow.style.transform = `translate3d(${(cx * -4).toFixed(2)}px, ${(cy * -2).toFixed(2)}px, 0)`;
      if (Math.abs(tx - cx) + Math.abs(ty - cy) > 0.001) {
        raf = window.requestAnimationFrame(frame);
      } else {
        running = false;
        last = 0;
      }
    };

    const wake = () => {
      if (running) return;
      running = true;
      last = 0;
      raf = window.requestAnimationFrame(frame);
    };

    const onMove = (e: PointerEvent) => {
      const r = stage.getBoundingClientRect();
      tx = Math.max(-1, Math.min(1, ((e.clientX - r.left) / r.width) * 2 - 1));
      ty = Math.max(-1, Math.min(1, ((e.clientY - r.top) / r.height) * 2 - 1));
      wake();
    };

    const onLeave = () => {
      tx = 0;
      ty = 0;
      wake();
    };

    stage.addEventListener("pointermove", onMove);
    stage.addEventListener("pointerleave", onLeave);
    return () => {
      stage.removeEventListener("pointermove", onMove);
      stage.removeEventListener("pointerleave", onLeave);
      window.cancelAnimationFrame(raf);
      device.style.transform = "";
      shadow.style.transform = "";
    };
  }, [reduced]);

  return (
    <header className="slate-hero" aria-labelledby="slate-hero-title">
      <p className="slate-hero__overline">
        <span className="slate-hero__maker">
          ONJI WORKS <span lang="ko">온지 워크스</span>
        </span>
        <span className="slate-hero__kind">
          E-INK WRITING SLATE <span lang="ko">전자잉크 필기 슬레이트</span>
        </span>
      </p>

      <h1 className="slate-hero__title" id="slate-hero-title">
        HANJI SLATE
      </h1>
      <p className="slate-hero__sub" lang="ko">
        한지 슬레이트 · 종이 컴퓨터
      </p>
      <p className="slate-hero__tagline">
        Paper that remembers. <span lang="ko">기억하는 종이.</span>
      </p>

      <div className="slate-hero__stage" ref={stageRef}>
        <div className="slate-hero__shadow" ref={shadowRef} aria-hidden="true" />
        <div className="slate-hero__device" ref={deviceRef}>
          <DeviceArt />
        </div>
      </div>

      <p className="slate-hero__specline">
        6.8&Prime; e-ink · 300 ppi · reads like the real thing{" "}
        <span lang="ko">진짜 종이처럼 읽힌다</span>
      </p>

      <p className="slate-hero__hint" aria-hidden="true">
        scroll <span lang="ko">아래로</span>
      </p>
    </header>
  );
}

"use client";

import { useRef, useState } from "react";
import { usePrefersReducedMotion } from "../hooks/usePrefersReducedMotion";

const FLASH_MS = 260; // 120ms flash + settle margin before the class drops

/**
 * Section 05 — footer on graphite, plus the e-ink flourish.
 *
 * The reading-mode toggle (light ↔ sepia) swaps the page's paper tokens
 * via data-mode on .slate-root, and — like a real e-paper page turn —
 * fires a 120ms full-invert flash: a hard-cut filter:invert(1) keyframe
 * on the root, no easing, because e-ink does not fade. The flash is
 * skipped entirely under prefers-reduced-motion (both here and by the
 * media query backstop in styles.css); the mode still switches instantly.
 */
export default function SlateFooter() {
  const [sepia, setSepia] = useState(false);
  const footerRef = useRef<HTMLElement | null>(null);
  const reduced = usePrefersReducedMotion();

  const toggleMode = () => {
    const next = !sepia;
    setSepia(next);
    const root = footerRef.current?.closest<HTMLElement>(".slate-root");
    if (!root) return;
    if (next) root.setAttribute("data-mode", "sepia");
    else root.removeAttribute("data-mode");
    if (reduced) return;
    // Rapid re-toggles ride the flash already in flight — real e-paper
    // batches refreshes the same way.
    if (root.classList.contains("is-refreshing")) return;
    root.classList.add("is-refreshing");
    window.setTimeout(() => root.classList.remove("is-refreshing"), FLASH_MS);
  };

  return (
    <footer className="slate-footer" ref={footerRef}>
      <div className="slate-footer__inner">
        <p className="slate-footer__giant">
          The last screen that lets you rest.
          <span lang="ko">쉬게 해주는 마지막 화면.</span>
        </p>

        <div className="slate-footer__mode">
          <p className="slate-footer__modeLabel" id="slate-mode-label">
            Reading mode <span lang="ko">독서 모드</span>
          </p>
          <button
            type="button"
            className="slate-footer__toggle"
            aria-pressed={sepia}
            aria-describedby="slate-mode-label"
            onClick={toggleMode}
          >
            <span
              className={`slate-footer__modeOpt${sepia ? "" : " is-active"}`}
            >
              LIGHT
            </span>
            <span
              className={`slate-footer__modeOpt${sepia ? " is-active" : ""}`}
            >
              SEPIA
            </span>
          </button>
          <p className="slate-footer__modeNote">
            The page refreshes like e-paper — one quiet blink.{" "}
            <span lang="ko">전자잉크처럼, 한 번 조용히 깜빡입니다.</span>
          </p>
        </div>

