  --slate-amber: #e8830c;         /* bright amber — decorative marks + dark ground
                                     only (2.4:1 on paper: never text on light) */
  --slate-amber-deep: #9a5504;    /* derived amber for functional accents on light
                                     ground — 4.6:1 on warm gray, 5.3:1 on paper */
  --slate-ink-soft: rgba(38, 38, 42, 0.72); /* ≈ #616061 — 5.3:1 on warm gray */
  --slate-paper-soft: rgba(247, 245, 240, 0.72); /* footer secondary — 7.9:1 */
  --slate-shell: #d8d4cb;         /* device shell, buttons, the magnesium back */
